const inputs = $input.all().map(i => i.json);
const requests = inputs.map(inp => ({
  custom_id: inp.custom_id || `${inp.agent_name||'agent'}-ch${inp.chapter_index||0}-ck${inp.chunk_index||1}`,
  method: 'POST', url: '/v1/chat/completions',
  body: {
    model: inp.model || 'gpt-4o',
    messages: [{role:'system',content:inp.system_prompt},{role:'user',content:inp.user_message}],
    max_tokens: inp.max_tokens || 16000,
    temperature: inp.temperature ?? 0.1,
    response_format: {type:'json_object'}
  }
}));
return [{json:{
  jsonl: requests.map(r=>JSON.stringify(r)).join('\n'),
  custom_ids: requests.map(r=>r.custom_id),
  agent_name: inputs[0].agent_name,
  model: inputs[0].model,
  course_id: inputs[0].course_id,
  pipeline_meta: inputs[0].pipeline_meta||{}
}}];

// After file upload — extract file_id and prepare batch creation
const resp = $input.first().json;
const fileId = resp.id;
if (!fileId) throw new Error(`File upload failed: ${JSON.stringify(resp)}`);

return [{ json: {
  file_id:     fileId,
  custom_id:   $('Build JSONL').first().json.custom_id,
  agent_name:  $('Build JSONL').first().json.agent_name,
  model:       $('Build JSONL').first().json.model,
  course_id:   $('Build JSONL').first().json.course_id,
  chapter_index: $('Build JSONL').first().json.chapter_index,
  chunk_index:   $('Build JSONL').first().json.chunk_index,
  pipeline_meta: $('Build JSONL').first().json.pipeline_meta
}}];

// After batch creation — return batch_id for the Poller
const resp = $input.first().json;
const batchId = resp.id;
if (!batchId) throw new Error(`Batch creation failed: ${JSON.stringify(resp)}`);

return [{ json: {
  batch_id:    batchId,
  status:      resp.status,
  file_id:     $('After Upload').first().json.file_id,
  custom_id:   $('After Upload').first().json.custom_id,
  agent_name:  $('After Upload').first().json.agent_name,
  model:       $('After Upload').first().json.model,
  course_id:   $('After Upload').first().json.course_id,
  chapter_index: $('After Upload').first().json.chapter_index,
  chunk_index:   $('After Upload').first().json.chunk_index,
  pipeline_meta: $('After Upload').first().json.pipeline_meta,
  submitted_at: new Date().toISOString()
}}];

const inp = $input.first().json;
const ts  = Date.now();
const agent = (inp.agent_name||'agent').replace(/[\s\/]/g,'_');
const filename = `${agent}_batch_${ts}.jsonl`;
const courseId = String(inp.course_id||'unknown');
const githubPath = `07_runs/${courseId}/scratch/${filename}`;
return [{ json: {
  ...inp,
  jsonl_base64:   Buffer.from(inp.jsonl).toString('base64'),
  github_path:    githubPath,
  github_filename: filename
}}];

